114→export const SpaceNodeContextMenuBase: FC<PropsWithChildren<{
115→  node: ISpaceTreeNode;
116→  trigger?: DropDownProps['trigger'];
117→  inEditing?: boolean;
118→  setInEditing?(v: boolean): void;
119→  // 是否限制展开按钮
120→  showExpandIcon?: boolean;
121→  className?: string;
122→  style?: CSSProperties;
123→  defaultEdit?: boolean;
124→  expandedRowKeys?: string[];
125→  setExpandedRowKeys?(v: string[]): void;
126→  // 当前列表所有的父id
127→  allParentIds?: string[];
128→  // 导出
129→  onExpand?(node: ISpaceTreeNode, v: boolean): void;
130→  // 重命名
131→  onRename?(newName: string, node: ISpaceTreeNode): Promise<void>;
132→  // 移动文件
133→  onMove?(node: ISpaceTreeNode): void;
134→  // 权限编辑
135→  onAuth?(node: ISpaceTreeNode): void;
136→  // 分享 mode=1 分享文件夹 mode=2 仅分享自己
137→  onShare?(node: ISpaceTreeNode, mode: 1 | 2): void;
138→  onCreate?(node: ISpaceTreeNode, type: SpaceTreeNodeType): void;
139→  /** 导入 */
140→  onImport?: (node: ISpaceTreeNode, type: 'folder' | 'file') => void;
141→  onCopyToPrivate?(node: ISpaceTreeNode): void;
142→}>> = (
143→  {
144→    style, allParentIds, setExpandedRowKeys, children, trigger, showExpandIcon, inEditing: inEditingProp, setInEditing: setInEditingProp,
145→    className, node, onRename, onMove, onAuth, onShare, onCreate, onCopyToPrivate, expandedRowKeys,
146→    onExpand, onImport,
147→  },
148→) => {
149→  const {
150→    data: {
151→      name, type, permissions,
152→    },
153→  } = node;
154→  const navigate = useNavigate();
155→  const inSpaceNodeTree = useMatch('/aio/workbench/:spaceId/node-tree');
156→  const [_, setDefaultExpandIds] = useStateLocal(useCallback(() => {
157→    return localNodeExpanded.get(node.data.spaceId) as Key[];
158→  }, [node.data.spaceId]), useCallback((v) => {
159→    localNodeExpanded.set(node.data.spaceId, v as string[]);
160→  }, [node.data.spaceId]));
161→  const [renameValidateR, setRenameValidateR] = useState<{
162→    status?: InputProps['status'];
163→    errMsg?: string;
164→  }>({});
165→  const { runAsync: renameRun, loading: renameLoading } = useRequest(
166→    (v: string) => v !== name ? onRename!(v, node) : Promise.resolve(),
167→    {
168→      manual: true,
169→      ready: !!onRename,
170→      onSuccess() {
171→        setInEditing(false);
172→        setRenameValidateR({});
173→      },
174→      onError(e) {
175→        setRenameValidateR({
176→          status: 'error', errMsg: e.message,
177→        });
178→      },
179→    },
180→  );
181→  const [inEditing, _setInEditing] = useStateSync(inEditingProp ?? false);
182→  const setInEditing = useCallback((v: boolean) => {
183→    setInEditingProp ? setInEditingProp(v) : _setInEditing(v);
184→  }, [_setInEditing, setInEditingProp]);
185→  const shareItem = useMemo<NonNullable<MenuProps['items']>[number] | null>(() => getShareItem(node, onShare), [node, onShare]);
186→
187→  const [unstarSpaceNode] = useUnstarSpaceNodeMutation();
188→  const [starSpaceNode] = useStarSpaceNodeMutation();
189→  const [copySpaceNode] = useCopySpaceNodeMutation();
190→  const [deleteSpaceNode] = useDeleteSpaceNodeMutation();
191→  const [saveOrUpdateLinkBySpaceNodeId] = useSaveOrUpdateLinkBySpaceNodeIdMutation();
192→  const [convertNodeToNextcloud] = useConvertNodeToNextcloudMutation();
193→
194→  const { modal: spaceNodeFolderModal, open: openSpaceNodeFolderModal } = useSpaceNodeFolderAIModal();
195→  const { modal: versionManagerModal, open: openVersionManagerModal } = useSpaceNodeVersionModal();
196→
197→  const { spaceNodeId } = useParams() as { spaceNodeId: string };
198→  const dispatch = useAppDispatch();
199→  const [getSpaceNodeTree] = useLazyGetSpaceNodeTreeQuery();
200→  const updateAIEnable = useCallback(async (isFolder: boolean, aiReferenceStatus: number, aiEnable?: boolean) => {
201→    if (!node) throw new Error('node not ready');
202→    if (isFolder) {
203→      openSpaceNodeFolderModal(node, aiReferenceStatus, node.data.spaceId);
204→    } else {
205→      await updateSpaceNodeAiCitation(node.data.id, !!aiEnable, node.data.spaceId);
206→      getSpaceNodeTree(node.data.spaceId);
207→
208→      if (node.data.id === spaceNodeId) {
209→      // 手动 invalidate，触发重新查询
210→        dispatch(spaceNodeApi.util.invalidateTags([{ type: 'SpaceNode', id: spaceNodeId }]));
211→      }
212→    }
213→  }, [node, spaceNodeId, dispatch, openSpaceNodeFolderModal, getSpaceNodeTree]);
214→
215→  const getMenuItems = useCallback((): MenuProps['items'] => {
216→    const downloadItem = exportAbleTypes.has(type) && permissions.exportable
217→      ? {
218→          key: 'export',
219→          label: <I18nText>downloadDoc</I18nText>,
220→          onClick: async () => {
221→            const confirm = type === SpaceTreeNodeType.OnlyOfficeExcel
222→              ? await antdApp.modal.confirm({
223→                  title: (
224→                    <span>
225→                      <I18nText>downloadPromptTitle</I18nText>
226→                    </span>
227→                  ),
228→                  content: <I18nText>downloadFormatNote</I18nText>,
229→                })
230→              : true;
231→            confirm && exportNode(node.data);
232→          },
233→          icon: <DownloadOutlined />,
234→        }
235→      : null;
236→    if (isPrivateMirror) {
237→      return filterNone([
238→        onCopyToPrivate
239→          ? {
240→              label: (
241→                <I18nText>
242→                  copyFileToPrivate
243→                </I18nText>
244→              ),
245→              key: 'copyFileToPrivate',
246→              onClick: () => {
247→                onCopyToPrivate(node);
248→              },
249→            }
250→          : null,
251→        downloadItem,
252→      ]);
253→    }
254→
255→    if (node.data.type === SpaceTreeNodeType.Link) {
256→      return [
257→        onMove && permissions.movable
258→          ? {
259→              key: 'move',
260→              label: t('move'),
261→              onClick() {
262→                onMove?.(node);
263→              },
264→              icon: <SvgIcon html={moveIcon} />,
265→            }
266→          : null,
267→        node.data.isStarred
268→          ? {
269→              key: 'unfavorite',
270→              label: <I18nText>unfavorite</I18nText>,
271→              onClick: async () => {
272→                await unstarSpaceNode(node.data.id).unwrap();
273→                antdApp.message.success(t('operationSuccess'));
274→              },
275→              icon: <SvgIcon html={starFilled} />,
276→            }
277→          : {
278→              key: 'favorite',
279→              label: <I18nText>favorite</I18nText>,
280→              onClick: async () => {
281→                await starSpaceNode(node.data.id).unwrap();
282→                antdApp.message.success(t('operationSuccess'));
283→              },
284→              icon: <SvgIcon html={starOutlined} />,
285→            },
286→        permissions.editable
287→          ? {
288→              key: 'change',
289→              label: t('change'),
290→              onClick: async () => {
291→                const data = await store.dispatch(spaceNodeApi.endpoints.getLinkBySpaceNodeId.initiate(node.data.id, { subscribe: false })).unwrap();
292→                openLinkNodeEditModal(async (values) => {
293→                  await saveOrUpdateLinkBySpaceNodeId({
294→                    id: data.id,
295→                    name: values.name,
296→                    link: values.link,
297→                  }).unwrap();
298→                  antdApp.message.success(t('operationSuccess'));
299→                }, {
300→                  name: data.name,
301→                  link: data.link,
302→                });
303→              },
304→              icon: <EditOutlined />,
305→            }
306→          : null,
307→        permissions.removable
308→          ? {
309→              key: 'delete',
310→              label: t('delete'),
311→              onClick: () => {
312→                antdApp.modal.confirm({
313→                  title: t('confirmToDeleteIt'),
314→                  type: 'warning',
315→                  onOk: () => {
316→                    return deleteSpaceNode({ spaceId: node.data.spaceId, spaceNodeId: node.data.id }).unwrap();
317→                  },
318→                });
319→              },
320→              icon: <SvgIcon html={deleteIcon} />,
321→            }
322→          : null,
323→      ];
324→    }
325→
326→    // 当前节点下所有的父id，包括自己
327→    const getNodeAllParentIds = () => {
328→      if (!node.children) return [];
329→      const r: string[] = [];
330→      forEachTree([node], (o) => {
331→        if (o.children?.length) {
332→          r.push(o.id);
333→        }
334→      });
335→      return r;
336→    };
337→
338→    const nodeAllParentIds = getNodeAllParentIds();
339→    const expandAllSubAble = !!nodeAllParentIds.length && !isUndefined(expandedRowKeys) && !isUndefined(setExpandedRowKeys);
340→    const expandAllAble = !!node.children?.length && !!allParentIds?.length && !isUndefined(expandedRowKeys) && !isUndefined(setExpandedRowKeys);
341→    const allSubExpanded = expandAllSubAble ? arrInclude(expandedRowKeys!, nodeAllParentIds) : false;
342→    const allExpanded = expandAllAble ? arrInclude(expandedRowKeys!, allParentIds!) : false;
343→
344→    const menuGroups: NonNullable<MenuProps['items']>[] = [
345→      filterNone<NonNullable<MenuProps['items']>[number]>([
346→        onCreate && permissions.childCreatable
347→          ? {
348→              key: 'create',
349→              label: <I18nText>create</I18nText>,
350→              children: nodeTypeList.map((type1) => ({
351→                key: type1,
352→                label: (
353→                  <TreeNodeItem nodeType={type1} nodeName={SpaceTreeNodeTypeText[type1]} />
354→                ),
355→                onClick: () => {
356→                  onCreate(node, type1);
357→                },
358→              })),
359→              icon: <SvgIcon html={createIcon} />,
360→            }
361→          : null,
362→        onImport && permissions.childCreatable
363→          ? {
364→              key: 'import',
365→              label: t('import'),
366→              children: [
367→                {
368→                  key: 'importFile',
369→                  label: t('file'),
370→                  onClick: () => onImport(node, 'file'),
371→                },
372→                {
373→                  key: 'importFolder',
374→                  label: t('folder'),
375→                  onClick: () => onImport(node, 'folder'),
376→                },
377→              ],
378→              icon: <ImportOutlined />,
379→            }
380→          : null,
381→        shareItem,
382→        {
383→          key: 'copyUrl',
384→          label: <I18nText>copyDocLink</I18nText>,
385→          onClick: () => copyToClipboard(getSpaceNodeURL(node.data)),
386→          icon: <SvgIcon html={copyUrlIcon} />,
387→        },
388→      ]),
389→      filterNone<NonNullable<MenuProps['items']>[number]>([
390→        node.data.isStarred
391→          ? {
392→              key: 'unfavorite',
