 12→interface ISpaceNodeMigrateModalContentProps {
 13→  nodeIds: string[];
 14→  onClose: () => void;
 15→}
 16→
 17→const SpaceNodeMigrateModalContent: React.FC<ISpaceNodeMigrateModalContentProps> = ({ onClose, nodeIds }) => {
 18→  const { data: spaces } = useGetManagedSpacesForMigrationQuery();
 19→  const spaceId = useParams().spaceId!;
 20→  const [loading, setLoading] = useState(false);
 21→  const [targetSpaceId, setTargetSpaceId] = useState<string>();
 22→
 23→  const runMigrate = useCallback(async () => {
 24→    if (!targetSpaceId) return;
 25→    setLoading(true);
 26→    const toastKey = `migrationTask-${Date.now()}`;
 27→    try {
 28→      const taskId = await createMigrationTask({ spaceNodeIds: nodeIds, targetSpaceId }, spaceId);
 29→      setLoading(false);
 30→      onClose();
 31→      antdApp.message.warning({ content: t('copyingDocuments'), duration: 0, key: toastKey });
 32→      while (true) {
 33→        await new Promise((res) => setTimeout(res, 2000));
 34→        const result = await getMigrationTask(taskId, spaceId);
 35→        if (result.status === 2) {
 36→          break;
 37→        }
 38→        if (result.status === 3) {
 39→          throw new Error(`taskId:${result.taskId} ${result.statusDesc}:${result.errorMessage}`);
 40→        }
 41→      }
 42→      antdApp.message.success(t('copyFileToPrivateSuccessTip'));
 43→    } catch (e) {
 44→      antdApp.modal.error({
 45→        content: `${e}`,
 46→      });
 47→    } finally {
 48→      setLoading(false);
 49→      antdApp.message.destroy(toastKey);
 50→    }
 51→  }, [nodeIds, targetSpaceId, spaceId, onClose]);
 52→
 53→  return (
 54→    <div>
 55→      <Radio.Group style={{ display: 'grid', justifyContent: 'start', gap: 4 }} value={targetSpaceId} onChange={(e) => setTargetSpaceId(e.target.value)}>
 56→        {spaces?.map((it) => (
 57→          <Radio value={it.spaceId} key={it.spaceId}>
 58→            <Space>
 59→              <Avatar
 60→                shape="square"
 61→                size={16}
 62→                style={{ backgroundColor: getAvatarRandomColor(it.spaceId) }}
 63→              >
 64→                {it.name[0]}
 65→              </Avatar>
 66→              <div className="text-ellipsis">
 67→                {it.name}
 68→              </div>
 69→            </Space>
 70→          </Radio>
 71→        ))}
 72→      </Radio.Group>
 73→      <Flex gap={8} justify="flex-end" style={{ marginTop: 16 }}>
 74→        <Button onClick={onClose}>{t('cancel')}</Button>
 75→        <Button
 76→          type="primary"
 77→          onClick={runMigrate}
 78→          disabled={!targetSpaceId}
 79→          loading={loading}
 80→        >{t('save')}
 81→        </Button>
 82→      </Flex>
 83→    </div>
 84→  );
 85→};
