 28→export const DocMigration = () => {
 29→  const { data: targetSpaces } = useGetManagedSpacesForMigrationQuery();
 30→  const dispatch = useAppDispatch();
 31→  // spaceId → { checked: Set<nodeId>, halfChecked: Set<nodeId> }
 32→  // checked 包含文件夹（用于父节点同步）；halfChecked 存储半选状态，渲染时 O(1) 查询
 33→  const [checkStateBySpace, setCheckStateBySpace] = useState<Record<string, SpaceCheckState>>({});
 34→  const [getSpaceNodeTree] = useLazyGetSpaceNodeTreeQuery();
 35→  const [targetSpaceId, setTargetSpaceId] = useState<string>();
 36→  const batchTask = useAppSelector(selectBatchMigrationTask);
 37→
 38→  const totalCheckedCount = useMemo(
 39→    () => Object.values(checkStateBySpace).reduce((sum, s) => sum + s.checked.size, 0),
 40→    [checkStateBySpace],
 41→  );
 42→
 43→  // 已有选中文件的源空间 ID 集合，对应的目标空间不可选
 44→  const checkedSourceSpaceIds = useMemo(
 45→    () => new Set(
 46→      Object.entries(checkStateBySpace)
 47→        .filter(([, s]) => s.checked.size > 0)
 48→        .map(([id]) => id),
 49→    ),
 50→    [checkStateBySpace],
 51→  );
 52→
 53→  // 若当前已选的 targetSpaceId 变为源空间（有文件被选中），则清空
 54→  useEffect(() => {
 55→    if (targetSpaceId && checkedSourceSpaceIds.has(targetSpaceId)) {
 56→      setTargetSpaceId(undefined);
 57→    }
 58→  }, [checkedSourceSpaceIds, targetSpaceId]);
 59→
 60→  const ableMigration = useMemo(
 61→    () => targetSpaceId !== undefined && totalCheckedCount > 0,
 62→    [targetSpaceId, totalCheckedCount],
 63→  );
 64→
 65→  const toggleNodeCheck = useCallback((spaceId: string, nodeId: string, checked: boolean, treeData: ISpaceTreeNodeCtx['spaceNodeTree']) => {
 66→    setCheckStateBySpace((prev) => {
 67→      const prevState = prev[spaceId];
 68→      const checkedSet = new Set(prevState?.checked);
 69→      const halfCheckedSet = new Set(prevState?.halfChecked);
 70→      const node = treeData?.spaceNodeMap[nodeId];
 71→
 72→      // 更新当前节点
 73→      if (checked) {
 74→        checkedSet.add(nodeId);
 75→        halfCheckedSet.delete(nodeId);
 76→      } else {
 77→        checkedSet.delete(nodeId);
 78→        halfCheckedSet.delete(nodeId);
 79→      }
 80→
 81→      // 递归更新所有子孙节点
 82→      traversalTree(node?.children ?? [], (child) => {
 83→        if (checked) {
 84→          checkedSet.add(child.data.id);
 85→          halfCheckedSet.delete(child.data.id);
 86→        } else {
 87→          checkedSet.delete(child.data.id);
 88→          halfCheckedSet.delete(child.data.id);
 89→        }
 90→      });
 91→
 92→      // 从当前节点向上更新每一层祖先节点的选中/半选状态
 93→      let currentParentId = node?.parentId;
 94→      while (currentParentId && currentParentId !== '0') {
 95→        const parentNode = treeData?.treeNodeMap[currentParentId];
 96→        if (!parentNode) break;
 97→
 98→        const allChecked = parentNode.children.length > 0
 99→          && parentNode.children.every((child) => checkedSet.has(child.data.id));
100→        const someChecked = !allChecked
101→          && parentNode.children.some((child) => checkedSet.has(child.data.id) || halfCheckedSet.has(child.data.id));
102→
103→        if (allChecked) {
104→          checkedSet.add(parentNode.data.id);
105→          halfCheckedSet.delete(parentNode.data.id);
106→        } else if (someChecked) {
107→          checkedSet.delete(parentNode.data.id);
108→          halfCheckedSet.add(parentNode.data.id);
109→        } else {
110→          checkedSet.delete(parentNode.data.id);
111→          halfCheckedSet.delete(parentNode.data.id);
112→        }
113→
114→        currentParentId = parentNode.parentId;
115→      }
116→
117→      return {
118→        ...prev,
119→        [spaceId]: { checked: checkedSet, halfChecked: halfCheckedSet },
120→      };
121→    });
122→  }, []);
123→
124→  const getSpaceTreeNodeProps = useCallback<NonNullable<ISpacesTreeProps['getSpaceTreeNodeProps']>>((spaceTreeNode, ctx) => {
125→    const { spaceId } = spaceTreeNode.data.data;
126→    const nodeId = spaceTreeNode.data.data.id;
127→    const spaceState = checkStateBySpace[spaceId];
128→    const isChecked = spaceState?.checked.has(nodeId) ?? false;
129→    const isHalfChecked = !isChecked && (spaceState?.halfChecked.has(nodeId) ?? false);
130→    return {
131→      ...ctx.originalProps,
132→      onClick: (e) => {
133→        e.preventDefault();
134→        toggleNodeCheck(spaceId, nodeId, !isChecked, ctx.spaceNodeTree);
135→      },
136→      suffixNode: (
137→        <Checkbox
138→          checked={isChecked}
139→          onClick={(e) => e.stopPropagation()}
140→          indeterminate={isHalfChecked}
141→          onChange={(e) => {
142→            e.nativeEvent.stopPropagation();
143→            toggleNodeCheck(spaceId, nodeId, !isChecked, ctx.spaceNodeTree);
144→          }}
145→        />
146→      ),
147→    };
148→  }, [checkStateBySpace, toggleNodeCheck]);
149→
150→  const toggleSpaceCheck = useCallback(async (spaceId: string, checked: boolean, ctx: ISpaceTreeNodeCtx) => {
151→    let treeData = ctx.spaceNodeTree;
152→    if (checked && !treeData) {
153→      // 空间站文件树未加载，勾选时先展开并加载空间站文件树
154→      ctx.setExpand(true);
155→      treeData = await getSpaceNodeTree(spaceId).unwrap();
156→    }
157→    setCheckStateBySpace((prev) => {
158→      if (!checked) {
159→        // 取消勾选：清空该空间所有节点状态
160→        return Object.fromEntries(Object.entries(prev).filter(([id]) => id !== spaceId));
161→      }
162→      if (!treeData) return prev;
163→      // 勾选：将该空间所有节点标记为 checked
164→      const checkedSet = new Set<string>();
165→      traversalTree(treeData.tree, (node) => {
166→        checkedSet.add(node.data.id);
167→      });
168→      return {
169→        ...prev,
170→        [spaceId]: { checked: checkedSet, halfChecked: new Set() },
171→      };
172→    });
173→  }, [getSpaceNodeTree]);
174→
175→  const getSpaceItemProps = useCallback<NonNullable<ISpacesTreeProps['getSpaceItemProps']>>((spaceItem, ctx) => {
176→    const { spaceId } = spaceItem.data;
177→    const spaceState = checkStateBySpace[spaceId];
178→    const treeData = ctx.spaceNodeTree;
179→
180→    // space 勾选状态从树节点状态派生，不单独存储
181→    let isChecked = false;
182→    let isHalfChecked = false;
183→    if (treeData) {
184→      isChecked = treeData.tree.length > 0
185→        && treeData.tree.every((n) => spaceState?.checked.has(n.data.id));
186→      isHalfChecked = !isChecked
187→        && treeData.tree.some((n) => spaceState?.checked.has(n.data.id) || spaceState?.halfChecked.has(n.data.id));
188→    } else if (spaceState && spaceState.checked.size > 0) {
189→      // 树未加载时沿用已有状态
190→      isChecked = spaceState.halfChecked.size === 0;
191→      isHalfChecked = !isChecked;
192→    }
193→
194→    return {
195→      ...ctx.originalProps,
196→      onClick: async (e) => {
197→        e.preventDefault();
198→        toggleSpaceCheck(spaceId, !isChecked, ctx);
199→      },
200→      suffixNode: (
201→        <Checkbox
202→          checked={isChecked}
203→          onClick={(e) => e.stopPropagation()}
204→          indeterminate={isHalfChecked}
205→          onChange={(e) => {
206→            e.nativeEvent.stopPropagation();
207→            toggleSpaceCheck(spaceId, !isChecked, ctx);
208→          }}
209→        />
210→      ),
211→    };
212→  }, [checkStateBySpace, toggleSpaceCheck]);
213→
214→  const startMigration = async (isRemained: boolean) => {
215→    if (!targetSpaceId) return;
216→    if (!isRemained && !await antdApp.modal.confirm({
217→      type: 'info',
218→      title: t('crossStationTransferIns'),
219→      content: migrationTip,
220→      width: 720,
221→      okText: t('nextStep'),
222→    })) return;
223→    let shouldRemain = isRemained;
224→
225→    if (!shouldRemain && !await antdApp.modal.confirm({
226→      type: 'info',
227→      title: t('transferConfirm'),
228→      width: 470,
229→      content: (
230→        <div>
231→          <Radio.Group
232→            className="space-y-2"
233→            onChange={(e) => {
234→              shouldRemain = e.target.value;
235→            }}
236→            defaultValue={shouldRemain}
237→            options={[
238→              { value: true, label: t('keepOriginal') },
239→              { value: false, label: t('deleteOriginal') },
240→            ]}
241→          />
242→        </div>
243→      ),
244→      okText: t('confirm'),
245→    })) return;
246→
247→    const items = Object.entries(checkStateBySpace)
248→      .map(([sourceSpaceId, state]) => ({ sourceSpaceId, spaceNodeIds: [...state.checked] }))
249→      .filter(({ spaceNodeIds }) => spaceNodeIds.length > 0);
250→
251→    const batchId = await createBatchMigrationTask({ items, targetSpaceId, isRemained: shouldRemain });
252→    const targetSpace = targetSpaces?.find((s) => s.spaceId === targetSpaceId);
253→    dispatch(dispatchAddBatchMigrationTask({
254→      batchId,
255→      to: { spaceId: targetSpaceId, spaceName: targetSpace?.name ?? '???' },
256→    }));
257→    setCheckStateBySpace({});
258→  };
259→
260→  return (
261→    <div className="h-full w-full flex flex-col overflow-hidden space-y-4">
262→      <div className="flex space-x-2">
263→        <div className="flex-1">
264→          <div>
265→            <span className="text-[18px] font-bold">
266→              {t('fileTransfer')}
267→            </span>
268→            <Button
269→              onClick={() => antdApp.modal.info({
270→                title: t('crossStationTransferIns'),
271→                content: migrationTip,
272→                width: 720,
273→              })}
274→              size="small"
275→              type="text"
276→              icon={<QuestionCircleOutlined />}
277→            />
278→          </div>
279→          <div className="text-[13px] text-color-text-tertiary">
280→            {t('transferDesc')}
281→          </div>
282→        </div>
283→        <Button
284→          type="primary"
285→          disabled={!ableMigration}
286→          loading={!!batchTask}
287→          onClick={() => startMigration(false)}
288→        >
289→          {t('startTransfer')}
290→        </Button>
291→        <Button
292→          type="primary"
293→          disabled={!ableMigration}
294→          loading={!!batchTask}
295→          onClick={() => startMigration(true)}
296→        >
297→          {t('startCopy')}
298→        </Button>
299→      </div>
300→      <div className="flex-1 flex space-x-4 overflow-hidden">
301→        <div className="bg-bg-base p-4 rounded-lg h-full flex-1 space-y-2 flex flex-col overflow-hidden">
302→          <div className="flex items-center justify-between">
303→            <div className="text-[16px] font-bold">
304→              {t('sourceSpace')}
305→            </div>
306→            {totalCheckedCount > 0 && (
307→              <span className="text-[13px] text-color-text-tertiary">
308→                {t('selectedFiles', { num: totalCheckedCount })}
309→              </span>
310→            )}
311→          </div>
312→          <div className="flex-1 overflow-auto">
313→            <SpacesTree getSpaceTreeNodeProps={getSpaceTreeNodeProps} getSpaceItemProps={getSpaceItemProps} />
314→          </div>
