 16→const BatchTaskItem: FC<{
 17→  task: IBatchMigrationTask;
 18→  onDone(): void;
 19→}> = ({ task, onDone }) => {
 20→  const dispatch = useAppDispatch();
 21→  const [isDone, setIsDone] = useState(false);
 22→  const { data } = useRequest(() => getBatchMigrationProgress(task.batchId), {
 23→    pollingInterval: 2000,
 24→    ready: !isDone,
 25→    onSuccess(v) {
 26→      if (v.tasks.every((sub) => sub.status === 2 || sub.status === 3)) {
 27→        const spaceIds = [...new Set([...v.tasks.map((sub) => sub.sourceSpaceId), task.to.spaceId])];
 28→        dispatch(spaceNodeApi.util.invalidateTags(spaceIds.map((id) => ({ type: 'SpaceNode', id: `LIST-${id}` }))));
 29→        onDone();
 30→        setIsDone(true);
 31→      }
 32→    },
 33→  });
 34→
 35→  const endedTasks = useMemo(() => data?.tasks.filter((sub) => sub.status === 2 || sub.status === 3) ?? [], [data]);
 36→  const errors = useMemo(() => data?.tasks.filter((sub) => sub.status === 3).map((sub) => sub.errorMessage) ?? [], [data]);
 37→
 38→  return (
 39→    <div className="mt-2">
 40→      <div className="mb-2">
 41→        <Progress
 42→          percent={
 43→            data
 44→              ? endedTasks.length / data.tasks.length * 100
 45→              : 0
 46→          }
 47→        />
 48→      </div>
 49→      {endedTasks.length === data?.tasks.length && (errors.length > 0
 50→        ? (
 51→            <div style={{ maxHeight: 200, overflowY: 'auto', color: 'var(--color-error)' }}>
 52→              {errors.map((error, index) => (
 53→                <div key={index}>
 54→                  <CloseSquareFilled className="mr-2" />
 55→                  {error}
 56→                </div>
 57→              ))}
 58→            </div>
 59→          )
 60→        : (
 61→            <div style={{ color: 'var(--color-success)' }}>
 62→              <CheckSquareFilled className="mr-2" />
